import { charttype, charttypenames, chartcategory, ZC_PLUGGABLE_VIZ } from "../../core/main-zc-init";
import { Registry } from "../../core/zc-registry";


export function exportCustomVisualAsAllowedChart(config, parser){
    /*
    config = {
        'name': '',
        'chartName: '',
        'chartNumber': '',
        'category': '',
        'processor': '',
        'axis': '',
        'singleNodeEvent': ''
    }
    */
   
    initialSetUp(config);
    setPluginConfig(config.name, parser);

}

function initialSetUp(config){
    charttype[config.chartName] = config.chartNumber;
    charttypenames.set(config.chartName, config.chartName);
    chartcategory[config.category].push(config.chartNumber);
}


function setPluginConfig(name, parser){
    ZC_PLUGGABLE_VIZ._types[name] = parser;
}


Registry.setComponent('exportCustomVisual', exportCustomVisualAsAllowedChart);